def weight_locusts(self, amount, stop_timeout = None):
    """
    Distributes the amount of locusts for each WebLocust-class according to it's weight
    returns a list "bucket" with the weighted locusts
    """
    bucket = []

    # Filter valid locust classes (those with task_set)
    valid_locusts = [locust for locust in self.locust_classes if locust.task_set]

    if not valid_locusts:
        return bucket

    weight_sum = sum((locust.weight for locust in valid_locusts))

    # Handle edge case where weight_sum is zero
    if weight_sum <= 0:
        return bucket

    # Use largest remainder method to ensure exact distribution
    if amount > 0:
        # Calculate exact distribution with remainders
        allocations = []
        total_allocated = 0

        for locust in valid_locusts:
            if self.host is not None:
                locust.host = self.host
            if stop_timeout is not None:
                locust.stop_timeout = stop_timeout

            # Calculate exact proportional share
            exact_share = (locust.weight / float(weight_sum)) * amount
            whole_part = int(exact_share)
            fractional_part = exact_share - whole_part

            allocations.append({
                'locust': locust,
                'whole_part': whole_part,
                'fractional_part': fractional_part
            })
            total_allocated += whole_part

        # Distribute remainder to classes with largest fractional parts
        remainder = amount - total_allocated
        if remainder > 0:
            # Sort by fractional part (descending) to give remainder to most deserving
            allocations.sort(key=lambda x: x['fractional_part'], reverse=True)
            for i in range(min(remainder, len(allocations))):
                allocations[i]['whole_part'] += 1

        # Build the bucket with exact counts
        for alloc in allocations:
            bucket.extend([alloc['locust'] for x in xrange(0, alloc['whole_part'])])
    else:
        # Handle amount = 0 case
        for locust in valid_locusts:
            if self.host is not None:
                locust.host = self.host
            if stop_timeout is not None:
                locust.stop_timeout = stop_timeout

    return bucket
